import { useEffect, useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { Textarea } from "@/components/ui/textarea";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Tabs,
  TabsContent,
  TabsList,
  TabsTrigger,
} from "@/components/ui/tabs";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";

import { apiClient, authService } from "@/App";
import { toast } from "sonner";

import {
  Plus,
  TrendingUp,
  TrendingDown,
  ArrowUpRight,
  ArrowDownRight,
  Wallet,
  Receipt,
  PieChart,
} from "lucide-react";

const FinancePortal = () => {
  const [payments, setPayments] = useState([]);
  const [transactions, setTransactions] = useState([]);
  const [summary, setSummary] = useState({});
  const [loading, setLoading] = useState(true);

  const [txnDialogOpen, setTxnDialogOpen] = useState(false);

  const user = authService.getUser();

  const [txnForm, setTxnForm] = useState({
    transaction_type: "income",
    category: "",
    amount: "",
    description: "",
    date: new Date().toISOString().split("T")[0],
  });

  const incomeCategories = [
    "Donations",
    "Government Grants",
    "Events",
    "Fundraising",
    "Other Income",
  ];

  const expenditureCategories = [
    "Salaries",
    "Utilities",
    "Supplies",
    "Maintenance",
    "Transport",
    "Food",
    "Equipment",
    "Other Expense",
  ];

  /* ---------------- SAFE NUMBER FORMATTER ---------------- */
  const money = (val) => {
    const num = Number(val || 0);
    return isNaN(num) ? 0 : num;
  };

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      setLoading(true);

      const [paymentsRes, txnRes, summaryRes] = await Promise.all([
        apiClient.get("/payments?approval_status=all"),
        apiClient.get("/finance/transactions"),
        apiClient.get("/finance/summary"),
      ]);

      setPayments(paymentsRes?.data || []);
      setTransactions(txnRes?.data || []);
      setSummary(summaryRes?.data || {});
    } catch (error) {
      console.error(error);
      toast.error("Failed to fetch finance data");
    } finally {
      setLoading(false);
    }
  };

  const handleAddTransaction = async (e) => {
    e.preventDefault();

    try {
      await apiClient.post("/finance/transactions", {
        ...txnForm,
        amount: Number(txnForm.amount || 0),
      });

      toast.success("Transaction recorded successfully");

      setTxnDialogOpen(false);

      setTxnForm({
        transaction_type: "income",
        category: "",
        amount: "",
        description: "",
        date: new Date().toISOString().split("T")[0],
      });

      fetchData();
    } catch (error) {
      console.error(error);

      toast.error(
        error?.response?.data?.detail || "Failed to record transaction"
      );
    }
  };

  if (loading) {
    return (
      <div className="flex justify-center items-center py-20 text-slate-400">
        Loading finance data...
      </div>
    );
  }

  return (
    <div className="space-y-6" data-testid="finance-portal">

      {/* HEADER */}
      <div className="bg-gradient-to-r from-emerald-600/20 to-teal-600/20 border border-emerald-500/20 rounded-2xl p-8">
        <h2 className="text-4xl font-bold text-white">
          Finance Portal
        </h2>

        <p className="text-emerald-300/70 mt-2 text-lg">
          Welcome back, {user?.full_name}
        </p>

        <p className="text-emerald-400/50 text-sm mt-1">
          Income, expenditure & school fee management
        </p>
      </div>

      {/* ACTION BUTTON */}
      <div className="flex justify-end">
        <Dialog open={txnDialogOpen} onOpenChange={setTxnDialogOpen}>
          <DialogTrigger asChild>
            <Button
              className="bg-emerald-600 hover:bg-emerald-700"
              data-testid="add-transaction-btn"
            >
              <Plus className="w-4 h-4 mr-2" />
              Add Transaction
            </Button>
          </DialogTrigger>

          <DialogContent>
            <DialogHeader>
              <DialogTitle>Record Transaction</DialogTitle>
            </DialogHeader>

            <form onSubmit={handleAddTransaction} className="space-y-4">

              <div className="space-y-2">
                <Label>Transaction Type *</Label>

                <Select
                  value={txnForm.transaction_type}
                  onValueChange={(v) =>
                    setTxnForm({
                      ...txnForm,
                      transaction_type: v,
                      category: "",
                    })
                  }
                >
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>

                  <SelectContent>
                    <SelectItem value="income">Income</SelectItem>
                    <SelectItem value="expenditure">Expenditure</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-2">
                <Label>Category *</Label>

                <Select
                  value={txnForm.category}
                  onValueChange={(v) =>
                    setTxnForm({
                      ...txnForm,
                      category: v,
                    })
                  }
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Select category" />
                  </SelectTrigger>

                  <SelectContent>
                    {(txnForm.transaction_type === "income"
                      ? incomeCategories
                      : expenditureCategories
                    ).map((category) => (
                      <SelectItem key={category} value={category}>
                        {category}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-2">
                <Label>Amount (KES) *</Label>

                <Input
                  type="number"
                  min="0"
                  required
                  value={txnForm.amount}
                  onChange={(e) =>
                    setTxnForm({
                      ...txnForm,
                      amount: e.target.value,
                    })
                  }
                />
              </div>

              <div className="space-y-2">
                <Label>Description *</Label>

                <Textarea
                  required
                  rows={3}
                  value={txnForm.description}
                  onChange={(e) =>
                    setTxnForm({
                      ...txnForm,
                      description: e.target.value,
                    })
                  }
                />
              </div>

              <div className="space-y-2">
                <Label>Date *</Label>

                <Input
                  type="date"
                  value={txnForm.date}
                  onChange={(e) =>
                    setTxnForm({
                      ...txnForm,
                      date: e.target.value,
                    })
                  }
                />
              </div>

              <Button
                type="submit"
                className="w-full bg-emerald-600 hover:bg-emerald-700"
              >
                Save Transaction
              </Button>

            </form>
          </DialogContent>
        </Dialog>
      </div>

      {/* SUMMARY CARDS */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">

        <Card className="border-l-4 border-l-emerald-500 bg-[#1A2332] border-[#1E293B]">
          <CardHeader className="pb-3">
            <div className="flex items-center justify-between">
              <CardTitle className="text-sm text-slate-400">
                Total Income
              </CardTitle>
              <ArrowUpRight className="w-5 h-5 text-emerald-400" />
            </div>
          </CardHeader>

          <CardContent>
            <div className="text-3xl font-bold text-emerald-400">
              KES {money(summary?.total_income).toLocaleString()}
            </div>
          </CardContent>
        </Card>

        <Card className="border-l-4 border-l-red-500 bg-[#1A2332] border-[#1E293B]">
          <CardHeader className="pb-3">
            <div className="flex items-center justify-between">
              <CardTitle className="text-sm text-slate-400">
                Total Expenditure
              </CardTitle>
              <ArrowDownRight className="w-5 h-5 text-red-400" />
            </div>
          </CardHeader>

          <CardContent>
            <div className="text-3xl font-bold text-red-400">
              KES {money(summary?.total_expenditure).toLocaleString()}
            </div>
          </CardContent>
        </Card>

        <Card className="border-l-4 border-l-blue-500 bg-[#1A2332] border-[#1E293B]">
          <CardHeader className="pb-3">
            <div className="flex items-center justify-between">
              <CardTitle className="text-sm text-slate-400">
                Running Balance
              </CardTitle>
              <Wallet className="w-5 h-5 text-blue-400" />
            </div>
          </CardHeader>

          <CardContent>
            <div className="text-3xl font-bold text-blue-400">
              KES {money(summary?.running_balance).toLocaleString()}
            </div>
          </CardContent>
        </Card>

        <Card className="border-l-4 border-l-amber-500 bg-[#1A2332] border-[#1E293B]">
          <CardHeader className="pb-3">
            <div className="flex items-center justify-between">
              <CardTitle className="text-sm text-slate-400">
                Fee Collections
              </CardTitle>
              <Receipt className="w-5 h-5 text-amber-400" />
            </div>
          </CardHeader>

          <CardContent>
            <div className="text-3xl font-bold text-amber-400">
              KES {money(summary?.total_fee_income).toLocaleString()}
            </div>
          </CardContent>
        </Card>

      </div>

      {/* TABS */}
<Tabs defaultValue="transactions" className="space-y-6">

  <TabsList className="bg-[#0F1A2A] border border-[#1E293B]">
    <TabsTrigger value="transactions">
      Transactions
    </TabsTrigger>

    <TabsTrigger value="payments">
      Payments ({payments?.length || 0})
    </TabsTrigger>
  </TabsList>

  {/* TRANSACTIONS TAB */}
  <TabsContent value="transactions">

    <Card className="bg-[#1A2332] border-[#1E293B]">

      <CardHeader>
        <CardTitle className="text-white">
          Transaction Ledger
        </CardTitle>
      </CardHeader>

      <CardContent>

        {(transactions?.length || 0) === 0 ? (
          <div className="text-center py-12 text-slate-500">
            <PieChart className="w-14 h-14 mx-auto mb-4 text-slate-600" />

            <p className="text-lg font-medium">
              No transactions recorded yet
            </p>
          </div>
        ) : (

          <div className="overflow-auto rounded-lg border border-[#1E293B]">

            <Table>

              <TableHeader>
                <TableRow className="border-[#1E293B]">
                  <TableHead>Date</TableHead>
                  <TableHead>Type</TableHead>
                  <TableHead>Category</TableHead>
                  <TableHead>Description</TableHead>
                  <TableHead>Amount</TableHead>
                  <TableHead>Status</TableHead>
                </TableRow>
              </TableHeader>

              <TableBody>

                {transactions.map((t) => {

                  const dateValue = t?.date || t?.created_at;
                  const formattedDate = dateValue
                    ? new Date(dateValue).toLocaleDateString()
                    : "—";

                  const amount = Number(t?.amount || 0);

                  return (
                    <TableRow key={t?.id || Math.random()} className="border-[#1E293B]">

                      <TableCell className="text-slate-300">
                        {formattedDate}
                      </TableCell>

                      <TableCell>
                        {t?.transaction_type === "income" ? (
                          <Badge className="bg-emerald-500/15 text-emerald-400">
                            <TrendingUp className="w-3 h-3 mr-1" />
                            Income
                          </Badge>
                        ) : (
                          <Badge className="bg-red-500/15 text-red-400">
                            <TrendingDown className="w-3 h-3 mr-1" />
                            Expense
                          </Badge>
                        )}
                      </TableCell>

                      <TableCell className="text-white">
                        {t?.category || "—"}
                      </TableCell>

                      <TableCell className="text-slate-400">
                        {t?.description || "—"}
                      </TableCell>

                      <TableCell
                        className={`font-bold ${
                          t?.transaction_type === "income"
                            ? "text-emerald-400"
                            : "text-red-400"
                        }`}
                      >
                        {t?.transaction_type === "income" ? "+" : "-"} KES{" "}
                        {amount.toLocaleString()}
                      </TableCell>

                      <TableCell>
                        <Badge
                          className={
                            t?.approval_status === "approved"
                              ? "bg-green-500/15 text-green-400"
                              : t?.approval_status === "rejected"
                              ? "bg-red-500/15 text-red-400"
                              : "bg-yellow-500/15 text-yellow-400"
                          }
                        >
                          {t?.approval_status || "pending"}
                        </Badge>
                      </TableCell>

                    </TableRow>
                  );
                })}

              </TableBody>

            </Table>

          </div>

        )}

      </CardContent>

    </Card>

  </TabsContent>

  {/* PAYMENTS TAB */}
  <TabsContent value="payments">

    <Card className="bg-[#1A2332] border-[#1E293B]">

      <CardHeader>
        <CardTitle className="text-white">
          Fee Payment Records
        </CardTitle>
      </CardHeader>

      <CardContent>

        {(payments?.length || 0) === 0 ? (
          <div className="text-center py-12 text-slate-500">
            No payment records found
          </div>
        ) : (

          <div className="overflow-auto rounded-lg border border-[#1E293B]">

            <Table>

              <TableHeader>
                <TableRow className="border-[#1E293B]">
                  <TableHead>Receipt</TableHead>
                  <TableHead>Amount</TableHead>
                  <TableHead>Method</TableHead>
                  <TableHead>Type</TableHead>
                  <TableHead>Status</TableHead>
                  <TableHead>Approval</TableHead>
                  <TableHead>Date</TableHead>
                </TableRow>
              </TableHeader>

              <TableBody>

                {payments.map((p) => {

                  const amount = Number(p?.amount || 0);

                  const dateValue = p?.created_at;
                  const formattedDate = dateValue
                    ? new Date(dateValue).toLocaleDateString()
                    : "—";

                  return (
                    <TableRow key={p?.id || Math.random()} className="border-[#1E293B]">

                      <TableCell className="font-medium text-white">
                        {p?.receipt_number || "—"}
                      </TableCell>

                      <TableCell className="font-bold text-emerald-400">
                        KES {amount.toLocaleString()}
                      </TableCell>

                      <TableCell className="text-slate-400 capitalize">
                        {p?.payment_method?.replace("_", " ") || "—"}
                      </TableCell>

                      <TableCell className="text-slate-400 capitalize">
                        {p?.payment_type || "—"}
                      </TableCell>

                      <TableCell>
                        <Badge
                          className={
                            p?.status === "completed"
                              ? "bg-green-500/15 text-green-400"
                              : "bg-yellow-500/15 text-yellow-400"
                          }
                        >
                          {p?.status || "pending"}
                        </Badge>
                      </TableCell>

                      <TableCell>
                        <Badge
                          className={
                            p?.approval_status === "approved"
                              ? "bg-green-500/15 text-green-400"
                              : p?.approval_status === "rejected"
                              ? "bg-red-500/15 text-red-400"
                              : "bg-yellow-500/15 text-yellow-400"
                          }
                        >
                          {p?.approval_status || "pending"}
                        </Badge>
                      </TableCell>

                      <TableCell className="text-slate-400">
                        {formattedDate}
                      </TableCell>

                    </TableRow>
                  );
                })}

              </TableBody>

            </Table>

          </div>

        )}

      </CardContent>

    </Card>

  </TabsContent>

</Tabs>

</div>
);
};

export default FinancePortal;
